import android.content.Context
import android.content.SharedPreferences

class AuthenticationManager(private val context: Context) {

    companion object {
        private const val PREF_NAME = "auth_manager_pref"
        private const val KEY_TOKEN = "token"
        private const val KEY_USER_ID = "user_id"
    }

    fun saveAuthToken(token: String, userId: String) {
        val sharedPrefs = getSharedPreferences()
        sharedPrefs.edit().putString(KEY_TOKEN, token).apply()
        sharedPrefs.edit().putString(KEY_USER_ID, userId).apply()
    }

    fun getSavedAuthToken(): String? {
        return getSharedPreferences().getString(KEY_TOKEN, null)
    }

    fun getUserID(): String? {
        return getSharedPreferences().getString(KEY_USER_ID, null)
    }

    private fun getSharedPreferences() = context.getSharedPreferences(PREF_NAME, Context.MODE_PRIVATE)

    fun logout() {
        val sharedPrefs = getSharedPreferences()
        sharedPrefs.edit().clear().apply()
    }
}